// TestRunsRedirectSessionsAndExecutions verifies Story 8 cleanup: legacy
// /sessions and /executions routes return 302 with a Sunset header, pointing
// to the layer-aware /runs page.
func TestRunsRedirectSessionsAndExecutions(t *testing.T) {
	dir := t.TempDir()
	srv := New(":0", dir)

	cases := []struct {
		name           string
		path           string
		wantLocPrefix  string
		wantLayerParam string
	}{
		{
			name:           "sessions redirects to runs?layer=run",
			path:           "/nodes/n1/projects/p1/sessions",
			wantLocPrefix:  "/nodes/n1/projects/p1/runs?",
			wantLayerParam: "run",
		},
		{
			name:           "sessions preserves query params",
			path:           "/nodes/n1/projects/p1/sessions?harness=codex",
			wantLocPrefix:  "/nodes/n1/projects/p1/runs?",
			wantLayerParam: "run",
		},
		{
			name:           "executions redirects to runs?layer=try",
			path:           "/nodes/n1/projects/p1/executions",
			wantLocPrefix:  "/nodes/n1/projects/p1/runs?",
			wantLayerParam: "try",
		},
		{
			name:          "executions detail redirects to runs/<id>",
			path:          "/nodes/n1/projects/p1/executions/exec-abc123",
			wantLocPrefix: "/nodes/n1/projects/p1/runs/exec-abc123",
		},
		{
			name:          "executions detail prepends exec- when missing",
			path:          "/nodes/n1/projects/p1/executions/abc123",
			wantLocPrefix: "/nodes/n1/projects/p1/runs/exec-abc123",
		},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			req := httptest.NewRequest("GET", tc.path, nil)
			req.RemoteAddr = "127.0.0.1:12345"
			w := httptest.NewRecorder()
			srv.Handler().ServeHTTP(w, req)

			if w.Code != http.StatusFound {
				t.Fatalf("expected 302, got %d: %s", w.Code, w.Body.String())
			}
			loc := w.Header().Get("Location")
			if loc == "" {
				t.Fatalf("missing Location header")
			}
			// Use prefix match so query-param ordering doesn't matter.
			if !startsWith(loc, tc.wantLocPrefix) {
				t.Fatalf("Location %q does not start with %q", loc, tc.wantLocPrefix)
			}
			if tc.wantLayerParam != "" {
				if got := queryParam(loc, "layer"); got != tc.wantLayerParam {
					t.Fatalf("layer param: got %q, want %q (loc=%s)", got, tc.wantLayerParam, loc)
				}
			}
			if got := w.Header().Get("Sunset"); got != runsRedirectSunset {
				t.Fatalf("Sunset header: got %q, want %q", got, runsRedirectSunset)
			}
			if got := w.Header().Get("Deprecation"); got != "true" {
				t.Fatalf("Deprecation header: got %q, want %q", got, "true")
			}
		})
	}
}

func startsWith(s, prefix string) bool {
	return len(s) >= len(prefix) && s[:len(prefix)] == prefix
}

func queryParam(rawURL, key string) string {
	idx := -1
	for i := 0; i < len(rawURL); i++ {
		if rawURL[i] == '?' {
			idx = i
			break
		}
	}
	if idx < 0 {
		return ""
	}
	q := rawURL[idx+1:]
	for len(q) > 0 {
		amp := len(q)
		for i := 0; i < len(q); i++ {
			if q[i] == '&' {
				amp = i
				break
			}
		}
		pair := q[:amp]
		eq := -1
		for i := 0; i < len(pair); i++ {
			if pair[i] == '=' {
				eq = i
				break
			}
		}
		if eq >= 0 && pair[:eq] == key {
			return pair[eq+1:]
		}
		if amp == len(q) {
			break
		}
		q = q[amp+1:]
	}
	return ""
}

